private async dispatchNotification(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  metadata: Record<string, unknown>;
  userId?: string;
}): Promise<void> {
  // Check user preferences before sending
  if (this.preferencesService && params.userId) {
    if (!this.preferencesService.shouldSendNotification(params.userId, params.channel, params.type)) {
      this.logger.info(
        `Notification ${params.type} suppressed for user ${params.userId} (preferences)`,
      );
      return;
    }
  }

  const now = new Date();
  const payload: NotificationPayload = {
    id: generateNotificationId(),
    type: params.type,
    channel: params.channel,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    metadata: params.metadata,
    createdAt: now,
  };

  const adapter = this.adapters.get(params.channel);

  if (adapter) {
    try {
      await adapter.send(payload);
      this.recordNotification(payload, 'sent', now);
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to send notification ${payload.id}: ${message}`);
      this.recordNotification(payload, 'failed', null);
    }
  } else {
    // No adapter registered — record as sent for backward compatibility
    // (in-memory tracking without an external delivery channel)
    this.recordNotification(payload, 'sent', now);
    this.logger.info(`Notification ${payload.id} recorded (no adapter for channel: ${params.channel})`);
  }
}

