it('should deliver notifications in order when events are emitted sequentially', async () => {
  const emailAdapter = new EmailAdapter({ from: 'noreply@taskflow.com' });
  service.registerAdapter(emailAdapter);

  const now = new Date();

  // Emit order:created then order:status-changed sequentially
  await eventBus.emit({
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
      ],
      total: 10,
      status: 'pending',
      createdAt: now,
      updatedAt: now,
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: now,
      updatedAt: now,
    },
    timestamp: now,
  } satisfies OrderCreatedEvent);

  await eventBus.emit({
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'alice@example.com',
      items: [],
      total: 10,
      status: 'confirmed',
      createdAt: now,
      updatedAt: now,
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: now,
  } satisfies OrderStatusChangedEvent);

  const notifications = service.getNotifications();
  expect(notifications).toHaveLength(2);
  // Order confirmation must arrive before status update
  expect(notifications[0]?.type).toBe('order_confirmation');
  expect(notifications[1]?.type).toBe('order_status_update');

  // Adapter should also have received them in order
  const emails = emailAdapter.getSentEmails();
  expect(emails).toHaveLength(2);
  expect(emails[0]?.subject).toContain('Order Confirmation');
  expect(emails[1]?.subject).toContain('Order Update');
});

